// Payload sent by WF11: patient_code, patient_id, clinic_id, name, phone (E.164), clinic_name, doctor_name, visit_date.
const data = $input.first().json.body || $input.first().json;
const name = String(data.name || data.patient_name || '').trim();
const phone = String(data.phone || '').trim();
const patientCode = String(data.patient_code || '').trim();
const patientId = String(data.patient_id || '').trim();
const clinicId = String(data.clinic_id || '').trim();
const clinic = String(data.clinic_name || 'our clinic').trim();
const doctor = String(data.doctor_name || 'your doctor').trim();
if (!clinicId || !/^[0-9a-f-]{36}$/i.test(clinicId)) return [{ json: { _skip: true, reason: 'Invalid clinic_id: ' + clinicId, patientCode } }];
if (!patientId || !/^[0-9a-f-]{36}$/i.test(patientId)) return [{ json: { _skip: true, reason: 'Invalid patient_id: ' + patientId, patientCode, clinic_id: clinicId } }];
if (!phone || !/^\+[1-9]\d{6,14}$/.test(phone)) return [{ json: { _skip: true, reason: 'Invalid phone: ' + phone, patientCode, clinic_id: clinicId, patient_id: patientId } }];
if (!name) return [{ json: { _skip: true, reason: 'Empty patient name', patientCode, clinic_id: clinicId, patient_id: patientId } }];
const messageBody = 'Hi ' + name + ', a very warm welcome to ' + clinic + '. We are glad you chose our clinic today. ' + doctor + ' will be with you shortly. Your details are safe with ' + clinic + ', and we will send your prescription and care updates to this number when they are ready. Please keep this number handy. See you inside!';
return [{ json: { _skip: false, _patient_id: patientId, patient_id: patientId, _patient_name: name, _phone: phone, _patient_code: patientCode, _clinic_id: clinicId, clinic_id: clinicId, _to_phone: 'whatsapp:' + phone, _clinic_name: clinic, _doctor_name: doctor, _message_type: 'patient_onboarding', _scheduled_date: new Date().toLocaleDateString('en-CA', { timeZone: $env.TIMEZONE || 'Asia/Kolkata' }), _content_sid: $env.TWILIO_CONTENT_PATIENT_ONBOARDING || $env.TWILIO_CONTENT_WELCOME || '', _content_variables: JSON.stringify({ '1': name, '2': clinic, '3': doctor }), _message_body: messageBody } }];
